import React, { useState, useEffect } from 'react';

const Trips = () => {
  const [itinerary, setItinerary] = useState([]);
  const [savedItineraries, setSavedItineraries] = useState([]);

  useEffect(() => {
    loadItinerary();
    loadSavedItineraries();
  }, []);

  const loadItinerary = () => {
    const saved = JSON.parse(localStorage.getItem('itinerary') || '[]');
    setItinerary(saved);
  };

  const loadSavedItineraries = () => {
    const saved = JSON.parse(localStorage.getItem('savedItineraries') || '[]');
    setSavedItineraries(saved);
  };

  const deleteItinerary = (id) => {
    if (window.confirm('Are you sure you want to delete this itinerary?')) {
      const updated = savedItineraries.filter(trip => trip.id !== id);
      setSavedItineraries(updated);
      localStorage.setItem('savedItineraries', JSON.stringify(updated));
    }
  };

  const editItinerary = (itinerary) => {
    // Store itinerary data for editing
    localStorage.setItem('editingItinerary', JSON.stringify(itinerary));
    window.location.href = '/budget';
  };

  const removeFromItinerary = (placeId) => {
    const updated = itinerary.filter(place => place.id !== placeId);
    setItinerary(updated);
    localStorage.setItem('itinerary', JSON.stringify(updated));
  };

  const getTotalCost = () => {
    return itinerary.reduce((total, place) => total + parseFloat(place.price), 0);
  };

  return (
    <div style={styles.container}>
      <div style={styles.header}>
        <h1 style={styles.title}>My Trips</h1>
        <a href="/budget" style={styles.createButton}>Create New Trip</a>
      </div>

      {savedItineraries.length > 0 && (
        <div style={styles.savedSection}>
          <h2 style={styles.sectionTitle}>Saved Itineraries</h2>
          {savedItineraries.map(trip => (
            <div key={trip.id} style={styles.itineraryContainer}>
              <div style={styles.itineraryHeader}>
                <h3 style={styles.itineraryTitle}>{trip.tripName}</h3>
                <div style={styles.itineraryInfo}>
                  <span>{trip.city}</span>
                  <span>{trip.days} Days</span>
                  <span>NPR {trip.totalCost}</span>
                </div>
                <div style={styles.itineraryActions}>
                  <button onClick={() => editItinerary(trip)} style={styles.editButton}>Edit</button>
                  <button onClick={() => deleteItinerary(trip.id)} style={styles.deleteButton}>Delete</button>
                </div>
              </div>
              {trip.startDate && trip.endDate && (
                <div style={styles.dateInfo}>
                  <span>📅 {new Date(trip.startDate).toLocaleDateString()} - {new Date(trip.endDate).toLocaleDateString()}</span>
                </div>
              )}
              <div style={styles.tripsGrid}>
                {trip.places.map(place => (
                  <div key={place.id} style={styles.tripCard}>
                    {place.image_url && (
                      <img 
                        src={`http://localhost:5000${place.image_url}`} 
                        alt={place.name}
                        style={styles.placeImage}
                      />
                    )}
                    <h4 style={styles.placeName}>{place.name}</h4>
                    <p style={styles.placeType}>{place.type}</p>
                    <p style={styles.placePrice}>NPR {place.price}</p>
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>
      )}

      <div style={styles.header}>
        <h1 style={styles.title}>Current Itinerary</h1>
        {itinerary.length > 0 && (
          <div style={styles.totalCost}>Total: NPR {getTotalCost()}</div>
        )}
      </div>

      {itinerary.length === 0 ? (
        <div style={styles.noTrips}>
          <h3>No places in current itinerary</h3>
          <p>Start exploring places to add to your itinerary!</p>
          <a href="/places" style={styles.exploreButton}>Explore Places</a>
        </div>
      ) : (
        <div style={styles.tripsGrid}>
          {itinerary.map(place => (
            <div key={place.id} style={styles.tripCard}>
              {place.image_url && (
                <img 
                  src={`http://localhost:5000${place.image_url}`} 
                  alt={place.name}
                  style={styles.placeImage}
                />
              )}
              <h3 style={styles.tripName}>{place.name}</h3>
              <p style={styles.cityName}>{place.city_name}</p>
              <p style={styles.tripBudget}>NPR {place.price}</p>
              <button 
                onClick={() => removeFromItinerary(place.id)}
                style={styles.removeButton}
              >
                Remove
              </button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

const styles = {
  container: {
    maxWidth: '1200px',
    margin: '0 auto',
    padding: '2rem',
    backgroundColor: '#f8fafc',
    minHeight: '100vh'
  },
  header: {
    backgroundColor: 'white',
    padding: '2rem',
    borderRadius: '12px',
    boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)',
    marginBottom: '2rem',
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center'
  },
  totalCost: {
    fontSize: '1.5rem',
    fontWeight: '700',
    color: '#059669'
  },
  title: {
    color: '#1f2937',
    fontSize: '2.5rem',
    fontWeight: '700',
    margin: 0
  },
  noTrips: {
    textAlign: 'center',
    padding: '3rem',
    backgroundColor: 'white',
    borderRadius: '12px',
    boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)'
  },
  exploreButton: {
    backgroundColor: '#3b82f6',
    color: 'white',
    padding: '0.75rem 1.5rem',
    borderRadius: '8px',
    textDecoration: 'none',
    fontWeight: '600',
    display: 'inline-block',
    marginTop: '1rem'
  },
  tripsGrid: {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))',
    gap: '2rem'
  },
  tripCard: {
    backgroundColor: 'white',
    padding: '2rem',
    borderRadius: '12px',
    boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)'
  },
  tripName: {
    fontSize: '1.25rem',
    fontWeight: '700',
    color: '#1f2937',
    margin: '0 0 1rem 0'
  },
  tripBudget: {
    color: '#059669',
    fontWeight: '600',
    margin: '0 0 0.5rem 0'
  },
  tripDate: {
    color: '#6b7280',
    fontSize: '0.9rem',
    margin: 0
  },
  placeImage: {
    width: '100%',
    height: '150px',
    objectFit: 'cover',
    borderRadius: '8px',
    marginBottom: '1rem'
  },
  cityName: {
    color: '#6b7280',
    fontSize: '0.9rem',
    margin: '0 0 0.5rem 0'
  },
  removeButton: {
    backgroundColor: '#ef4444',
    color: 'white',
    border: 'none',
    padding: '0.5rem 1rem',
    borderRadius: '6px',
    cursor: 'pointer',
    fontSize: '0.9rem',
    fontWeight: '600',
    width: '100%',
    marginTop: '1rem'
  },
  savedSection: {
    marginBottom: '3rem'
  },
  savedInfo: {
    display: 'flex',
    gap: '2rem',
    fontSize: '1.2rem',
    fontWeight: '600',
    color: '#059669'
  },
  dateInfo: {
    backgroundColor: '#f0f9ff',
    padding: '1rem',
    borderRadius: '8px',
    marginBottom: '2rem',
    textAlign: 'center',
    fontSize: '1.1rem',
    fontWeight: '500',
    color: '#0369a1'
  }
};

export default Trips;
